  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires deriving the force law for a thermally isolated (adiabatic) polymer chain. This involves calculating the internal energy as a function of extension and then finding the derivative with respect to extension. I will split this into calculating the partition function/internal energy and then performing the thermodynamic derivative.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "For a freely jointed chain of n segments of length l, derive the expression for the internal energy U as a function of the end-to-end distance x under adiabatic conditions. Assume the system follows the microcanonical ensemble or that the temperature changes such that entropy is constant. Focus on finding the relationship between U and x."
    },
    {
      "label": "helper_2",
      "instructions": "Given the internal energy U(x) derived for a thermally isolated freely jointed polymer chain, calculate the force F(x) using the thermodynamic relation F = dU/dx. Ensure the result is expressed in terms of n, l, and x."
    }
  ],
  "synthesis_brief": "Combine the internal energy expression U(x) from helper 1 and the derivative dU/dx from helper 2 to provide the final force law F(x) with the correct coefficients and powers of x."
}

